import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

const MasterData = () => {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    truckId: '',
    truckType: '',
    driver: '',
    status: 'onprogress',
    date: '',
    image: null,
  });

  const [trucks, setTrucks] = useState([]);
  const [search, setSearch] = useState('');

  const fetchTrucks = async () => {
    try {
      const res = await fetch('http://localhost:5000/api/trucks');
      const data = await res.json();
      if (res.ok) {
        setTrucks(data);
      } else {
        console.error(data.message);
      }
    } catch (err) {
      console.error('Gagal mengambil data dari server', err);
    }
  };

  useEffect(() => {
    fetchTrucks();
  }, []);

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (name === 'image') {
      setForm((prevForm) => ({ ...prevForm, image: files[0] }));
    } else {
      setForm((prevForm) => ({ ...prevForm, [name]: value }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const formData = new FormData();
    formData.append('truckId', form.truckId);
    formData.append('truckType', form.truckType);
    formData.append('driver', form.driver);
    formData.append('status', form.status);
    formData.append('date', form.date);
    if (form.image) {
      formData.append('image', form.image);
    }

    try {
      const res = await fetch('http://localhost:5000/api/trucks', {
        method: 'POST',
        body: formData,
      });

      const data = await res.json();
      if (res.ok) {
        alert('Truck berhasil disimpan!');
        setForm({ truckId: '', truckType: '', driver: '', status: 'onprogress', date: '', image: null });
        fetchTrucks();
      } else {
        alert(data.message || 'Gagal menyimpan data truk');
      }
    } catch (err) {
      alert('Gagal terhubung ke server');
      console.error(err);
    }
  };

  const handleDelete = async (truckId) => {
    const confirmDelete = window.confirm('Apakah Anda yakin ingin menghapus data truck ini?');
    if (confirmDelete) {
      try {
        const res = await fetch(`http://localhost:5000/api/trucks/${truckId}`, {
          method: 'DELETE',
        });
        const data = await res.json();
        if (res.ok) {
          alert('Truck berhasil dihapus!');
          fetchTrucks(); // Refresh data
        } else {
          alert(data.message || 'Gagal menghapus data truk');
        }
      } catch (err) {
        alert('Gagal terhubung ke server');
        console.error(err);
      }
    }
  };

  const handleEdit = (truckId) => {
    navigate(`/edit-truck/${truckId}`);
  };

  const filteredTrucks = trucks.filter(
    (truck) =>
      truck.truckId.toString().includes(search.toLowerCase()) ||
      truck.truckType.toLowerCase().includes(search.toLowerCase()) ||
      truck.driver.toLowerCase().includes(search.toLowerCase()) ||
      truck.status.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="flex min-h-screen bg-gray-100">
      <aside className="bg-gray-800 text-white w-64 p-6 flex flex-col justify-between">
        <div>
          <div className="flex flex-col items-center mb-6">
            <img src="https://via.placeholder.com/50" alt="Admin Icon" className="rounded-full mb-2" />
            <h2 className="font-semibold text-lg">Admin</h2>
          </div>

          <nav className="space-y-6">
            <Link to="/master-data" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Master Data</Link>
            <Link to="/tracking" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Tracking</Link>
            <Link to="/info-driver" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Info Driver</Link>
          </nav>
        </div>

        <nav className="space-y-6 mt-6">
          <Link to="/settings" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Settings</Link>
          <Link to="/logout" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Logout</Link>
        </nav>
      </aside>

      <main className="flex-1 p-6">
        <header className="flex items-center justify-between mb-6">
          <div className="flex items-center space-x-4">
            <h1 className="text-2xl font-bold">Dashboard</h1>
            <span className="text-lg font-medium text-gray-600">/ Truck</span>
          </div>
        </header>

        <section className="mb-6 bg-white p-6 rounded-lg shadow-md space-y-4">
          <h2 className="text-xl font-semibold mb-2">Tambah Truck Baru</h2>
          <form onSubmit={handleSubmit} className="space-y-4" encType="multipart/form-data">
            <div>
              <label className="block text-sm font-medium text-gray-700">Truck ID</label>
              <input type="number" name="truckId" value={form.truckId} onChange={handleChange} required className="mt-1 p-2 border border-gray-300 rounded w-full" />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">Truck Type</label>
              <select name="truckType" value={form.truckType} onChange={handleChange} required className="mt-1 p-2 border border-gray-300 rounded w-full">
                <option value="">-- Pilih Jenis Truck --</option>
                <option value="Dump Truck">Dump Truck</option>
                <option value="Fuso">Fuso</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">Driver</label>
              <input type="text" name="driver" value={form.driver} onChange={handleChange} required className="mt-1 p-2 border border-gray-300 rounded w-full" />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">Status</label>
              <select name="status" value={form.status} onChange={handleChange} required className="mt-1 p-2 border border-gray-300 rounded w-full">
                <option value="onprogress">On Progress</option>
                <option value="finished">Finished</option>
                <option value="trouble">Trouble</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">Choose a Date</label>
              <input type="date" name="date" value={form.date} onChange={handleChange} required className="mt-1 p-2 border border-gray-300 rounded w-full" />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">Gambar Truck</label>
              <input type="file" name="image" accept="image/*" onChange={handleChange} className="mt-1 p-2 border border-gray-300 rounded w-full" />
            </div>

            <button type="submit" className="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600">Simpan Truck</button>
          </form>
        </section>

        <section className="mb-4">
          <input
            type="text"
            placeholder="Cari berdasarkan ID, tipe, driver, atau status"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="p-2 border border-gray-300 rounded w-full"
          />
        </section>

        <section className="overflow-x-auto">
          <table className="min-w-full bg-white rounded-lg shadow-md">
            <thead>
              <tr className="bg-gray-200 text-gray-600 text-left">
                <th className="py-3 px-4">Truck ID</th>
                <th className="py-3 px-4">Truck Type</th>
                <th className="py-3 px-4">Driver</th>
                <th className="py-3 px-4">Status</th>
                <th className="py-3 px-4">Date</th>
                <th className="py-3 px-4">Image</th>
                <th className="py-3 px-4">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredTrucks.length > 0 ? (
                filteredTrucks.map((truck) => (
                  <tr key={truck.truckId} className="border-t">
                    <td className="py-3 px-4">{truck.truckId}</td>
                    <td className="py-3 px-4">{truck.truckType}</td>
                    <td className="py-3 px-4">{truck.driver}</td>
                    <td className="py-3 px-4">{truck.status}</td>
                    <td className="py-3 px-4">{truck.date}</td>
                    <td className="py-3 px-4">
                      {truck.image && <img src={truck.image} alt="Truck" className="w-16 h-16 object-cover" />}
                    </td>
                    <td className="py-3 px-4 flex space-x-2">
                      <button
                        className="text-yellow-600"
                        onClick={() => handleEdit(truck._id)}
                      >
                        Edit
                      </button>
                      <button
                        className="text-red-600"
                        onClick={() => handleDelete(truck._id)} // using truck._id here
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="7" className="py-3 px-4 text-center text-gray-500">
                    Tidak ada data
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </section>
      </main>
    </div>
  );
};

export default MasterData;
